import React, { useState, useCallback, useMemo } from 'react';
import PropTypes from 'prop-types';

// Sub-component for performance optimization
const TreeNode = React.memo(({ node, onSelect, activeId }) => {
  const hasChildren = node.children && node.children.length > 0;
  const isActive = activeId === node.id;

  return (
    <div className={`node-wrapper ${isActive ? 'active' : ''}`}>
      <div className="node-row" onClick={() => onSelect(node)}>
        <span className="icon">{hasChildren ? '📂' : '📄'}</span>
        <span className="name">{node.name}</span>
      </div>
      {hasChildren && (
        <div className="child-group">
          {node.children.map(child => (
            <TreeNode key={child.id} node={child} onSelect={onSelect} activeId={activeId} />
          ))}
        </div>
      )}
    </div>
  );
});

const ConceptTreeCore = ({ data = [] }) => {
  const [activeNode, setActiveNode] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');

  const handleSelect = useCallback((node) => {
    setActiveNode(node);
  }, []);

  const filteredData = useMemo(() => {
    if (!searchQuery) return data;
    return data.filter(n => n.name.toLowerCase().includes(searchQuery.toLowerCase()));
  }, [data, searchQuery]);

  return (
    <main className="concept-root">
      <div className="controls">
        <input 
          type="text" 
          placeholder="Search concepts..." 
          onChange={(e) => setSearchQuery(e.target.value)} 
        />
      </div>
      <section className="layout-split">
        <div className="tree-view">
          {filteredData.map(node => (
            <TreeNode 
              key={node.id} 
              node={node} 
              onSelect={handleSelect} 
              activeId={activeNode?.id} 
            />
          ))}
        </div>
        <aside className="info-panel">
          {activeNode ? (
            <div className="card">
              <h2 style={{ color: '#61afef' }}>{activeNode.name}</h2>
              <hr />
              <p>{activeNode.details || 'Detailed concept analysis pending...'}</p>
              <button className="btn-primary">Edit Node</button>
            </div>
          ) : (
            <div className="empty-state">Select a node to view details</div>
          )}
        </aside>
      </section>
      <style>{` 
        .concept-root { display: grid; grid-template-rows: auto 1fr; height: 100vh; background: #1a1a1a; color: #fff; }
        .layout-split { display: grid; grid-template-columns: 350px 1fr; gap: 1rem; overflow: hidden; }
        .tree-view { overflow-y: auto; padding: 20px; border-right: 1px solid #333; }
        .node-row { padding: 8px; cursor: pointer; transition: 0.2s; border-radius: 4px; }
        .node-row:hover { background: rgba(255,255,255,0.1); }
        .active .node-row { background: #2c313c; border-left: 4px solid #61afef; }
      `}</style>
    </main>
  );
};

ConceptTreeCore.propTypes = {
  data: PropTypes.array.isRequired
};

export default ConceptTreeCore;
